from __future__ import annotations


def integrator_dashboard_html() -> str:
    return r'''<!doctype html>
<html lang="ru">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Bitrix24 Engineering Audit — AI-BIT</title>
<style>
:root{color-scheme:light;--bg:#f5f6f8;--surface:#fff;--surface2:#fafbfc;--line:#e3e6ea;--text:#17191c;--muted:#6f747c;--accent:#5e6ad2;--critical:#b42318;--high:#c9364f;--medium:#a9670b;--low:#187653;--ok:#16835d;--mono:ui-monospace,SFMono-Regular,Consolas,"Liberation Mono",monospace}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px/1.45 Inter,ui-sans-serif,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}button,input,select{font:inherit}main{max-width:1700px;margin:auto;padding:24px 26px 80px}.header{display:flex;align-items:flex-start;justify-content:space-between;gap:20px;margin-bottom:16px}.eyebrow{font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase;color:var(--accent)}h1{font-size:25px;letter-spacing:-.03em;margin:4px 0}.muted{color:var(--muted)}.actions{display:flex;gap:8px}.btn{border:1px solid var(--line);background:#fff;color:var(--text);border-radius:7px;padding:8px 11px;cursor:pointer}.btn:hover{background:#f7f7f8}.btn.primary{background:#202124;color:#fff;border-color:#202124}.metrics{display:grid;grid-template-columns:repeat(6,minmax(120px,1fr));gap:8px;margin-bottom:12px}.metric{background:var(--surface);border:1px solid var(--line);border-radius:9px;padding:12px}.metric span{display:block;color:var(--muted);font-size:10px;text-transform:uppercase;letter-spacing:.05em}.metric b{display:block;font-size:23px;margin-top:4px}.tabs{display:flex;gap:4px;overflow:auto;border-bottom:1px solid var(--line);margin-bottom:12px}.tab{border:0;background:transparent;color:#666b73;padding:9px 11px;cursor:pointer;border-bottom:2px solid transparent;white-space:nowrap}.tab.active{color:var(--text);border-bottom-color:var(--accent);font-weight:700}.view{display:none}.view.active{display:block}.panel{background:var(--surface);border:1px solid var(--line);border-radius:10px;overflow:hidden;margin-bottom:10px}.panel-head{display:flex;justify-content:space-between;align-items:center;gap:12px;padding:12px 14px;border-bottom:1px solid var(--line);background:var(--surface2)}.panel-head h2{font-size:14px;margin:0}.count{font:11px var(--mono);color:var(--muted)}table{width:100%;border-collapse:collapse}th,td{padding:9px 11px;text-align:left;border-bottom:1px solid #edf0f2;vertical-align:top}th{font-size:10px;text-transform:uppercase;letter-spacing:.05em;color:var(--muted);background:#fbfcfd}tr:last-child td{border-bottom:0}.mono{font-family:var(--mono);font-size:11px;word-break:break-word}.badge{display:inline-flex;align-items:center;border-radius:999px;padding:3px 7px;font-size:10px;font-weight:800;text-transform:uppercase}.badge.critical{background:#fee4e2;color:var(--critical)}.badge.high{background:#ffeaed;color:var(--high)}.badge.medium{background:#fff3dc;color:var(--medium)}.badge.low,.badge.ok{background:#e7f6ef;color:var(--ok)}.badge.error,.badge.failed,.badge.missing{background:#fee4e2;color:var(--critical)}.badge.partial{background:#fff3dc;color:var(--medium)}.filters{display:flex;gap:7px;flex-wrap:wrap;margin-bottom:10px}.filters select,.filters input{border:1px solid var(--line);background:#fff;border-radius:7px;padding:7px 9px}.filters input{min-width:260px}.module-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.module-card{background:#fff;border:1px solid var(--line);border-radius:9px;padding:12px}.module-card h3{font-size:13px;margin:0 0 8px}.module-row{display:flex;justify-content:space-between;padding:3px 0;color:var(--muted)}details.issue{background:#fff;border:1px solid var(--line);border-radius:9px;margin-bottom:7px;overflow:hidden}details.issue[open]{border-color:#cfd3da}details.issue summary{list-style:none;display:grid;grid-template-columns:92px 180px minmax(260px,1fr) 150px;gap:10px;align-items:center;padding:10px 12px;cursor:pointer}details.issue summary::-webkit-details-marker{display:none}.issue-body{border-top:1px solid var(--line);padding:12px;display:grid;grid-template-columns:1fr 1fr;gap:8px}.box{background:#fafbfc;border:1px solid #e9ecef;border-radius:7px;padding:10px}.box b{display:block;font-size:10px;text-transform:uppercase;letter-spacing:.05em;color:var(--muted);margin-bottom:5px}.wide{grid-column:1/-1}.evidence{margin:0;padding-left:18px}.empty{padding:28px;text-align:center;color:var(--muted);background:#fff;border:1px solid var(--line);border-radius:9px}.source-list{display:grid;grid-template-columns:repeat(4,1fr);gap:7px}.source-item{display:flex;justify-content:space-between;align-items:center;background:#fff;border:1px solid var(--line);border-radius:8px;padding:9px 10px}.dot{width:8px;height:8px;border-radius:50%;background:#c7cbd1}.dot.ok{background:var(--ok)}.error-panel{display:none;padding:20px;border:1px solid #f1c5cb;background:#fff7f8;color:#8f2433;border-radius:10px;margin-bottom:12px}.error-panel.show{display:block}@media(max-width:1050px){.metrics{grid-template-columns:repeat(3,1fr)}.module-grid,.source-list{grid-template-columns:repeat(2,1fr)}details.issue summary{grid-template-columns:80px 140px 1fr}.issue-body{grid-template-columns:1fr}}@media(max-width:650px){main{padding:16px 12px 70px}.header{display:block}.actions{margin-top:10px}.metrics{grid-template-columns:repeat(2,1fr)}.module-grid,.source-list{grid-template-columns:1fr}details.issue summary{grid-template-columns:75px 1fr}.summary-source{display:none}.filters input{min-width:100%;width:100%}}
</style>
</head>
<body>
<main>
 <div class="header"><div><div class="eyebrow">Bitrix24 Engineering Audit</div><h1>Аудит интегратора</h1><div class="muted">Факт → объект → evidence → исправление → приёмка</div></div><div class="actions"><button class="btn" id="download" type="button">JSON</button><button class="btn primary" id="refresh" type="button">Обновить</button></div></div>
 <div id="error" class="error-panel"></div>
 <div id="metrics" class="metrics"></div>
 <nav class="tabs" id="tabs"><button class="tab active" data-view="overview">Обзор</button><button class="tab" data-view="findings">Замечания</button><button class="tab" data-view="rest">REST</button><button class="tab" data-view="reference">Эталонный diff</button><button class="tab" data-view="todo">Technical TODO</button><button class="tab" data-view="sources">Источники</button></nav>
 <section id="overview" class="view active"></section>
 <section id="findings" class="view"></section>
 <section id="rest" class="view"></section>
 <section id="reference" class="view"></section>
 <section id="todo" class="view"></section>
 <section id="sources" class="view"></section>
</main>
<script>
(()=>{'use strict';
const q=(s,r=document)=>r.querySelector(s);const qa=(s,r=document)=>Array.from(r.querySelectorAll(s));const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));let data=null;
const sevName={critical:'critical',high:'high',medium:'medium',low:'low'};
function badge(value){const v=String(value||'unknown').toLowerCase();return `<span class="badge ${esc(v)}">${esc(v)}</span>`}
function metric(label,value){return `<div class="metric"><span>${esc(label)}</span><b>${esc(value??0)}</b></div>`}
function panel(title,body,count=''){return `<div class="panel"><div class="panel-head"><h2>${esc(title)}</h2><span class="count">${esc(count)}</span></div>${body}</div>`}
function renderMetrics(){const s=data.summary||{},i=data.inventory||{};q('#metrics').innerHTML=[['Issues',s.total],['Critical',s.critical],['High',s.high],['REST failed',i.rest_failed],['Sources',`${i.available_sources||0}/${i.total_sources||0}`],['Reference',i.reference_checks]].map(x=>metric(x[0],x[1])).join('')}
function renderOverview(){const modules=data.module_summary||[];const cards=modules.length?`<div class="module-grid">${modules.map(x=>`<div class="module-card"><h3>${esc(x.module)}</h3><div class="module-row"><span>Всего</span><b>${x.total||0}</b></div><div class="module-row"><span>Critical / High</span><b>${(x.critical||0)+(x.high||0)}</b></div><div class="module-row"><span>Medium / Low</span><b>${(x.medium||0)+(x.low||0)}</b></div></div>`).join('')}</div>`:'<div class="empty">Подтверждённых замечаний нет.</div>';q('#overview').innerHTML=panel('Модули',cards,`${modules.length} modules`)+panel('Принцип аудита',`<div style="padding:13px 14px" class="mono">${esc(data.principle||'')}</div>`,data.version||'')}
function issueHtml(x){const evidence=(x.evidence||[]).length?`<ul class="evidence">${x.evidence.map(v=>`<li class="mono">${esc(v)}</li>`).join('')}</ul>`:'нет';return `<details class="issue" data-severity="${esc(x.severity)}" data-module="${esc(x.module)}"><summary>${badge(x.severity)}<span class="mono">${esc(x.module)}</span><b>${esc(x.title)}</b><span class="mono summary-source">${esc(x.source)}</span></summary><div class="issue-body"><div class="box"><b>Объект</b><span class="mono">${esc(x.object_ref||'не определён')}</span></div><div class="box"><b>Факт</b>${esc(x.finding)}</div><div class="box wide"><b>Evidence</b>${evidence}</div><div class="box"><b>Исправить</b>${esc(x.fix)}</div><div class="box"><b>Приёмка</b>${esc(x.verification)}</div>${Object.keys(x.technical||{}).length?`<div class="box wide"><b>Raw technical context</b><pre class="mono" style="white-space:pre-wrap;margin:0">${esc(JSON.stringify(x.technical,null,2))}</pre></div>`:''}</div></details>`}
function renderFindings(){const rows=data.issues||[];const modules=[...new Set(rows.map(x=>x.module))].sort();q('#findings').innerHTML=`<div class="filters"><select id="sevFilter"><option value="all">Severity: all</option><option>critical</option><option>high</option><option>medium</option><option>low</option></select><select id="moduleFilter"><option value="all">Module: all</option>${modules.map(x=>`<option>${esc(x)}</option>`).join('')}</select><input id="textFilter" placeholder="ID, метод, объект, текст ошибки"></div><div id="issueList">${rows.length?rows.map(issueHtml).join(''):'<div class="empty">Подтверждённых замечаний нет.</div>'}</div>`;['#sevFilter','#moduleFilter','#textFilter'].forEach(s=>q(s)?.addEventListener('input',filterIssues))}
function filterIssues(){const sev=q('#sevFilter')?.value||'all',mod=q('#moduleFilter')?.value||'all',text=(q('#textFilter')?.value||'').toLowerCase();qa('#issueList .issue').forEach(el=>{const okSev=sev==='all'||el.dataset.severity===sev;const okMod=mod==='all'||el.dataset.module===mod;const okText=!text||el.textContent.toLowerCase().includes(text);el.style.display=okSev&&okMod&&okText?'block':'none'})}
function renderRest(){const rows=data.rest_checks||[];const body=rows.length?`<table><thead><tr><th>Status</th><th>Method</th><th>Capability</th><th>HTTP</th><th>Duration</th><th>Error</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${badge(x.status)}</td><td class="mono">${esc(x.method)}</td><td>${esc(x.capability)}</td><td class="mono">${esc(x.http_status??'')}</td><td class="mono">${esc(x.duration_ms??'')}</td><td class="mono">${esc(x.error||'')}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">REST probes отсутствуют.</div>';q('#rest').innerHTML=panel('REST probes',body,`${rows.length} checks`)}
function renderReference(){const rows=data.reference_diff||[];const body=rows.length?`<table><thead><tr><th>Status</th><th>Module</th><th>Capability</th><th>Object</th><th>Evidence</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${badge(x.status)}</td><td>${esc(x.module)}</td><td><b>${esc(x.capability)}</b></td><td class="mono">${esc(x.object_ref||'')}</td><td class="mono">${esc((x.evidence||[]).join(' | '))}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">Reference diff отсутствует.</div>';q('#reference').innerHTML=panel('Эталонный diff',body,`${rows.length} checks`)}
function renderTodo(){const rows=data.technical_todo||[];const body=rows.length?`<table><thead><tr><th>#</th><th>Priority</th><th>Module</th><th>Object</th><th>Task</th><th>Acceptance</th><th>Source</th></tr></thead><tbody>${rows.map(x=>`<tr><td class="mono">${x.priority}</td><td>${badge(x.severity)}</td><td>${esc(x.module)}</td><td class="mono">${esc(x.object_ref||'')}</td><td>${esc(x.task)}</td><td>${esc(x.acceptance)}</td><td class="mono">${esc(x.source)}</td></tr>`).join('')}</tbody></table>`:'<div class="empty">Технических задач нет.</div>';q('#todo').innerHTML=panel('Technical TODO',body,`${rows.length} tasks`)}
function renderSources(){const rows=Object.entries(data.sources||{});q('#sources').innerHTML=panel('Источники evidence',rows.length?`<div class="source-list" style="padding:10px">${rows.map(([k,v])=>`<div class="source-item"><span class="mono">${esc(k)}</span><span class="dot ${v?'ok':''}"></span></div>`).join('')}</div>`:'<div class="empty">Нет источников.</div>',`${rows.filter(x=>x[1]).length}/${rows.length}`)}
function render(){renderMetrics();renderOverview();renderFindings();renderRest();renderReference();renderTodo();renderSources()}
async function load(){const b=q('#refresh'),error=q('#error');if(b){b.disabled=true;b.textContent='Загрузка…'}error?.classList.remove('show');try{const r=await fetch('/integrator-diagnostics/latest?_='+Date.now(),{cache:'no-store'});if(!r.ok)throw new Error(`HTTP ${r.status}: ${await r.text()}`);data=await r.json();render()}catch(e){if(error){error.textContent='Ошибка загрузки: '+e.message;error.classList.add('show')}}finally{if(b){b.disabled=false;b.textContent='Обновить'}}}
q('#tabs')?.addEventListener('click',e=>{const b=e.target.closest('.tab[data-view]');if(!b)return;qa('.tab,.view').forEach(x=>x.classList.remove('active'));b.classList.add('active');q('#'+b.dataset.view)?.classList.add('active')});q('#refresh')?.addEventListener('click',load);q('#download')?.addEventListener('click',()=>{if(!data)return;const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='ai-bit-integrator-audit.json';a.click();URL.revokeObjectURL(a.href)});load();
})();
</script>
</body>
</html>'''
